curl -s -X POST 'http://localhost:8108/collections/catalog/overrides/phone_exact' \
  -H "X-TYPESENSE-API-KEY: xyz" \
  -H "Content-Type: application/json" \
  -d '{
    "rule": {
      "query": "phone",
      "match": "exact"
    },
    "includes": [
      {"id": "p1", "position": 1},
      {"id": "p7", "position": 2}
    ],
    "excludes": [
      {"id": "p2"}
    ]
  }'
echo
echo
# Override 2: Contains "deal" - pin p3 to position 1
