curl -s -X POST 'http://localhost:8108/collections/catalog/overrides/deal_contains' \
  -H "X-TYPESENSE-API-KEY: xyz" \
  -H "Content-Type: application/json" \
  -d '{
    "rule": {
      "query": "deal",
      "match": "contains"
    },
    "includes": [
      {"id": "p3", "position": 1}
    ]
  }'
echo
echo
# Override 3: Dynamic filter for "{brand} phone"
# Faceted field is required (brand is facetable). Query pattern uses {brand}.
# remove_matched_tokens must be true. filter_by uses the placeholder.
echo "=== Override 3: dynamic brand filter ==="
curl -s -X POST 'http://localhost:8108/collections/catalog/overrides/brand_phone_filter' \
  -H "X-TYPESENSE-API-KEY: xyz" \
  -H "Content-Type: application/json" \
  -d '{
    "rule": {
      "query": "{brand} phone",
      "match": "contains"
    },
    "filter_by": "brand:={brand}",
    "remove_matched_tokens": true
  }'
echo

